+  }
+
+  /**
+   * @brief Set the filter config value by name.
+   *
+   * @attention The pass into value type is double, witch will be cast to the actual type inside the
+   * filter. The actual type can be queried by the filter config schema returned by @ref
+   * getConfigSchemaVec.
