+    Error::handle(&error);
+  }
+
+  /**
+   * @brief Get the Config Value object by name.
+   *
+   * @attention The returned value type has been casted to double inside the filter. The actual type
+   * can be queried by the filter config schema returned by
+   * @ref getConfigSchemaVec.
+   *
+   * @param configName  The name of the config.
+   * @return double The value of the config.
+   */
+  virtual double getConfigValue(const std::string &configName) const {
