+void OBCameraNode::startPipeline() {
+  pipeline_ = std::make_unique<ob::Pipeline>(device_);
+  pipeline_->start(config_, [this](std::shared_ptr<ob::FrameSet> frame_set) {
+    frameSetCallback(std::move(frame_set));
+  });
+}
