+  os << "fy : " << rgb_intrinsic.fy << "\n";
+  os << "cx : " << rgb_intrinsic.cx << "\n";
+  os << "cy : " << rgb_intrinsic.cy << "\n";
+  os << "width : " << rgb_intrinsic.width << "\n";
